package com.example.battleship.controller;

import com.example.battleship.view.SceneManager;
import javafx.fxml.FXML;
import javafx.scene.control.Button;
import javafx.scene.control.TextField;

public class MenuController {

    // fx:id names must match those defined in FXML
    @FXML private TextField txtNickname;
    @FXML private Button btnNewGame;
    @FXML private Button btnContinue;
    @FXML private Button btnExit;

    @FXML
    public void initialize() {
        // disable "New Game" until nickname is provided
        btnNewGame.disableProperty().bind(txtNickname.textProperty().isEmpty());
        btnContinue.disableProperty().set(false); // make available if save exists (could be improved)
    }

    @FXML
    private void handleNewGame() {
        String playerNickname = txtNickname.getText().trim();
        System.out.println("Nueva partida para: " + playerNickname);
        SceneManager.getInstance().changeScene("game-view.fxml");
    }

    @FXML
    private void handleContinue() {
        System.out.println("Continuar partida...");
        SceneManager.getInstance().changeScene("game-view.fxml");
    }

    @FXML
    private void handleExit() {
        System.exit(0);
    }
}

package com.example.battleship.game;

import com.example.battleship.model.players.HumanPlayer;
import com.example.battleship.model.players.MachinePlayer;
import com.example.battleship.model.enums.CellState;
import com.example.battleship.model.Coordinate;

import java.io.Serializable;

/**
 * Simple game manager that holds the two players and the turn state.
 * Serializable so it can be saved/loaded by GameSaver.
 */
public class GameManager implements Serializable {
    private static final long serialVersionUID = 1L;

    private final HumanPlayer human;
    private final MachinePlayer machine;
    private boolean humanTurn;
    private String nickname;

    public GameManager(String nickname){
        this.nickname = nickname;
        this.human = new HumanPlayer();
        this.machine = new MachinePlayer();
        this.humanTurn = true;
    }

    public HumanPlayer getHuman(){return human;}
    public MachinePlayer getMachine(){return machine;}
    public boolean isHumanTurn(){return humanTurn;}
    public void setHumanTurn(boolean t){this.humanTurn = t;}
    public String getNickname(){return nickname;}
    public void setNickname(String nickname){this.nickname = nickname;}

    /**
     * Apply a shot by the human to the machine board and return the result.
     */
    public com.example.battleship.model.enums.CellState humanShoot(Coordinate c) throws Exception{
        CellState result = machine.getBoard().shoot(c);
        // If water, switch turn
        if (result == CellState.WATER){
            humanTurn = false;
        }
        return result;
    }

    public com.example.battleship.model.enums.CellState machineShoot() throws Exception{
        Coordinate c = machine.chooseShotTarget();
        CellState result = human.getBoard().shoot(c);
        machine.registerShotResult(c, result);
        if (result == CellState.WATER){
            humanTurn = true;
        }
        return result;
    }
}

package com.example.battleship.model;

import com.example.battleship.model.enums.CellState;
import com.example.battleship.model.enums.Orientation;
import com.example.battleship.model.ships.Ship;
import com.example.battleship.model.enums.ShipType;
import com.example.battleship.model.exceptions.InvalidCoordinateException;
import com.example.battleship.model.exceptions.RepeatedShotException;
import com.example.battleship.model.exceptions.ShipOverLapException;
import javafx.scene.input.ScrollEvent;

import java.util.*;

import static com.example.battleship.model.enums.Orientation.HORIZONTAL;
import static com.example.battleship.model.enums.Orientation.VERTICAL;

public class Board {
    private final Map<Coordinate,Cell> board;
    private final Fleet fleet;
    public Board() {
        board=new HashMap<>();
        fleet= new Fleet();
        fillBoard();
    }

    private void fillBoard() {
        for (int row=0;row<=9;row++){
            for (int col=0; col<=9; col++){
                Coordinate coordinate= new Coordinate(row,col);
                board.put(coordinate, new Cell(coordinate));
            }
        }
    }

    public Map<Coordinate,Cell> getBoard(){
        return Collections.unmodifiableMap(board);
    }

    public void placeShip(Coordinate coordinate, Orientation orientation, ShipType shipType)throws ShipOverLapException{
        List<Coordinate> coordinatesShip=calculateShipCoordinates(coordinate, orientation, shipType);
        if (validateCells(coordinatesShip)){
            List<Cell> cells=new ArrayList<>();
            for (Coordinate coordinates: coordinatesShip){
                cells.add(getCell(coordinates));
            }
            Ship ship = ShipFactory.createShip(shipType,orientation,cells);
            fleet.addShip(ship);
            for (Cell cell: cells){
                cell.assignShip(ship);
            }
        }
    }

    private boolean validateCells(List<Coordinate>coordinatesList)throws ShipOverLapException{
        for (Coordinate coordinate: coordinatesList){
            if(getCell(coordinate).hasShip()){
                throw new ShipOverLapException("Cell is already occupied by another ship");
            }
        }
        return true;
    }

    private List<Coordinate> calculateShipCoordinates(Coordinate start, Orientation orientation, ShipType type){
        List<Coordinate> coordinates= new ArrayList<>();
        if (orientation==HORIZONTAL){
            int startRow=start.getRow();
            int endCol=start.getCol();
            for (int startCol=start.getCol(); startCol<endCol+type.getSize(); startCol++){
                coordinates.add(new Coordinate(startRow,startCol));
            }
        }
        else if (orientation==VERTICAL){
            int startCol=start.getCol();
            int endRow=start.getRow();
            for (int startRow=start.getRow(); startRow<endRow+type.getSize(); startRow++){
                coordinates.add(new Coordinate(startRow,startCol));
            }
        }else{
            throw new IllegalArgumentException("it is not vertical and horizontal");
        }
        return coordinates;
    }

    public Cell getCell(Coordinate coordinate){
        if (coordinate == null) {
            throw new IllegalArgumentException("Coordinate cannot be null");
        }
        return board.get(coordinate);
    }

    public CellState shoot(Coordinate coordinate)throws RepeatedShotException {
        return getCell(coordinate).receiveShot();
    }

    public boolean isFleetDefeated(){
        return fleet.isFleetSunk();
    }
}

package com.example.battleship.model;

import com.example.battleship.model.enums.CellState;
import com.example.battleship.model.enums.Orientation;
import com.example.battleship.model.ships.Ship;
import com.example.battleship.model.enums.ShipType;
import com.example.battleship.model.exceptions.InvalidCoordinateException;
import com.example.battleship.model.exceptions.RepeatedShotException;
import com.example.battleship.model.exceptions.ShipOverLapException;
import javafx.scene.input.ScrollEvent;

import java.io.Serializable;
import java.util.*;

import static com.example.battleship.model.enums.Orientation.HORIZONTAL;
import static com.example.battleship.model.enums.Orientation.VERTICAL;

public class Board implements Serializable {
    private static final long serialVersionUID = 1L;
    private final Map<Coordinate,Cell> board;
    private final Fleet fleet;
    private transient List<BoardListener> listeners = new ArrayList<>();
    public Board() {
        board=new HashMap<>();
        fleet= new Fleet();
        fillBoard();
    }

    private void fillBoard() {
        for (int row=0;row<=9;row++){
            for (int col=0; col<=9; col++){
                Coordinate coordinate= new Coordinate(row,col);
                board.put(coordinate, new Cell(coordinate));
            }
        }
    }

    public Map<Coordinate,Cell> getBoard(){
        return Collections.unmodifiableMap(board);
    }

    public Fleet getFleet(){
        return fleet;
    }

    public void addListener(BoardListener listener){
        if (listener==null) return;
        if (listeners==null) listeners=new ArrayList<>();
        listeners.add(listener);
    }

    public void removeListener(BoardListener listener){
        if (listeners!=null) listeners.remove(listener);
    }

    public void placeShip(Coordinate coordinate, Orientation orientation, ShipType shipType)throws ShipOverLapException{
        List<Coordinate> coordinatesShip=calculateShipCoordinates(coordinate, orientation, shipType);
        if (validateCells(coordinatesShip)){
            List<Cell> cells=new ArrayList<>();
            for (Coordinate coordinates: coordinatesShip){
                cells.add(getCell(coordinates));
            }
            Ship ship = ShipFactory.createShip(shipType,orientation,cells);
            fleet.addShip(ship);
            for (Cell cell: cells){
                cell.assignShip(ship);
                // notify listeners about ship placement per cell
                if (listeners!=null){
                    for (BoardListener l: listeners){
                        try{ l.onCellUpdated(cell.getCoordinate(), cell.getCellState()); }catch(Exception ignore){}
                    }
                }
            }
        }
    }

    private boolean validateCells(List<Coordinate>coordinatesList)throws ShipOverLapException{
        for (Coordinate coordinate: coordinatesList){
            if(getCell(coordinate).hasShip()){
                throw new ShipOverLapException("Cell is already occupied by another ship");
            }
        }
        return true;
    }

    private List<Coordinate> calculateShipCoordinates(Coordinate start, Orientation orientation, ShipType type){
        List<Coordinate> coordinates= new ArrayList<>();
        if (orientation==HORIZONTAL){
            int startRow=start.getRow();
            int endCol=start.getCol();
            for (int startCol=start.getCol(); startCol<endCol+type.getSize(); startCol++){
                coordinates.add(new Coordinate(startRow,startCol));
            }
        }
        else if (orientation==VERTICAL){
            int startCol=start.getCol();
            int endRow=start.getRow();
            for (int startRow=start.getRow(); startRow<endRow+type.getSize(); startRow++){
                coordinates.add(new Coordinate(startRow,startCol));
            }
        }else{
            throw new IllegalArgumentException("it is not vertical and horizontal");
        }
        return coordinates;
    }

    public Cell getCell(Coordinate coordinate){
        if (coordinate == null) {
            throw new IllegalArgumentException("Coordinate cannot be null");
        }
        return board.get(coordinate);
    }

    public CellState shoot(Coordinate coordinate)throws RepeatedShotException {
        CellState result = getCell(coordinate).receiveShot();
        if (listeners!=null){
            for (BoardListener l: listeners){
                try{ l.onCellUpdated(coordinate, result);}catch(Exception ignore){}
            }
        }
        return result;
    }

    public boolean isFleetDefeated(){
        return fleet.isFleetSunk();
    }
}

package com.example.battleship.model;

import com.example.battleship.model.enums.CellState;

/**
 * Listener interface for Board changes. Implementations (UI) should register to
 * receive notifications when a cell changes state or when ships are placed.
 */
public interface BoardListener {
    void onCellUpdated(Coordinate coordinate, CellState newState);
}

package com.example.battleship.model;

import com.example.battleship.model.enums.CellState;
import com.example.battleship.model.exceptions.RepeatedShotException;
import com.example.battleship.model.ships.Ship;

public class Cell {
    private CellState cellState;
    private final Coordinate coordinate;
    private Ship ship;
    public Cell(Coordinate coordinate){
        if (coordinate==null){
            throw new IllegalArgumentException("Coordinate cannot be null");
        }
        this.coordinate=coordinate;
        cellState=CellState.EMPTY;
        ship=null;
    }
    public CellState getCellState(){return cellState;}
    public void setCellState(CellState cellState){
        if (cellState == null) {
            throw new IllegalArgumentException("State cannot be null");
        }
        this.cellState=cellState;}
    public Coordinate getCoordinate(){return coordinate;}
    public Ship getShip(){return ship;}
    public void assignShip(Ship ship){
        if (ship==null){
            throw new IllegalArgumentException("Ship cant be null");
        }
        if (hasShip()){
            throw new IllegalStateException("cell"+coordinate+" is already occupied");
        }
        this.ship=ship;
        this.cellState=CellState.OCCUPIED;
    }
    public boolean hasShip(){
        return ship!=null;
    }
    public CellState receiveShot()throws RepeatedShotException{
        if (cellState==CellState.EMPTY){
            setCellState(CellState.WATER);
            return cellState;
        }
        else if (cellState==CellState.OCCUPIED){
            setCellState(CellState.HIT);
            if(ship.registerHit()){
               return cellState;
            }
        }else{
            throw new RepeatedShotException("Cell already shot, current state: "+cellState.getSymbol(), cellState );
        }
        return cellState;
    }
    @Override
    public String toString(){
        return "Cell"+coordinate.toString()+"[State="+cellState+"]";
    }
}

package com.example.battleship.model;

import com.example.battleship.model.enums.CellState;
import com.example.battleship.model.exceptions.RepeatedShotException;
import com.example.battleship.model.ships.Ship;
import java.io.Serializable;

public class Cell implements Serializable {
    private static final long serialVersionUID = 1L;
    private CellState cellState;
    private final Coordinate coordinate;
    private Ship ship;
    public Cell(Coordinate coordinate){
        if (coordinate==null){
            throw new IllegalArgumentException("Coordinate cannot be null");
        }
        this.coordinate=coordinate;
        cellState=CellState.EMPTY;
        ship=null;
    }
    public CellState getCellState(){return cellState;}
    public void setCellState(CellState cellState){
        if (cellState == null) {
            throw new IllegalArgumentException("State cannot be null");
        }
        this.cellState=cellState;}
    public Coordinate getCoordinate(){return coordinate;}
    public Ship getShip(){return ship;}
    public void assignShip(Ship ship){
        if (ship==null){
            throw new IllegalArgumentException("Ship cant be null");
        }
        if (hasShip()){
            throw new IllegalStateException("cell"+coordinate+" is already occupied");
        }
        this.ship=ship;
        this.cellState=CellState.OCCUPIED;
    }
    public boolean hasShip(){
        return ship!=null;
    }
    public CellState receiveShot()throws RepeatedShotException{
        if (cellState==CellState.EMPTY){
            setCellState(CellState.WATER);
            return cellState;
        }
        else if (cellState==CellState.OCCUPIED){
            setCellState(CellState.HIT);
            if(ship.registerHit()){
               return cellState;
            }
        }else{
            throw new RepeatedShotException("Cell already shot, current state: "+cellState.getSymbol(), cellState );
        }
        return cellState;
    }
    @Override
    public String toString(){
        return "Cell"+coordinate.toString()+"[State="+cellState+"]";
    }
}

package com.example.battleship.model;

import com.example.battleship.model.exceptions.InvalidCoordinateException;

public class Coordinate {
    private final int row;
    private final int col;
    public Coordinate(int row, int col) throws InvalidCoordinateException{
        if(validate(row,col)){
            this.row=row;
            this.col=col;
        }else{
            throw new InvalidCoordinateException("Row or Col outside the table", row ,col);
        }
    }
    public int getRow(){return row;}
    public int getCol(){return col;}
    private boolean validate(int row, int col){
        return row>=0 && row<=9 && col>=0 && col<=9;
    }
    @Override
    public String toString(){
        char columnLetter=(char)('A'+col);
        String stringColumnLetter=String.valueOf(columnLetter);
        return stringColumnLetter+(row+1);
    }
    @Override
    public boolean equals(Object obj) {
        if (this==obj){
            return true;
        }
        if(!(obj instanceof Coordinate other)){return false;}
        return row==other.row && col==other.col;
    }
    @Override
    public int hashCode(){
        return 31*row+col;
    }

}

